import type { Metadata, Viewport } from "next";
import Link from "next/link";
import { Inter, JetBrains_Mono } from "next/font/google";
import "./globals.css";

const inter = Inter({
  subsets: ["latin"],
  variable: "--font-sans",
  display: "swap",
});

const jetbrainsMono = JetBrains_Mono({
  subsets: ["latin"],
  variable: "--font-mono",
  display: "swap",
});

const siteUrl =
  process.env.NEXT_PUBLIC_SITE_URL && process.env.NEXT_PUBLIC_SITE_URL.startsWith("http")
    ? process.env.NEXT_PUBLIC_SITE_URL
    : "https://sales-marketing-network.app";

export const metadata: Metadata = {
  metadataBase: new URL(siteUrl),
  title: {
    default: "Sales Marketing Network",
    template: "%s • Sales Marketing Network",
  },
  description:
    "Collaborative sales workspace for team pipeline execution, lead management, and real-time analytics.",
  applicationName: "Sales Marketing Network",
  keywords: [
    "sales",
    "marketing",
    "CRM",
    "pipeline tracking",
    "team analytics",
    "dashboard",
  ],
  authors: [{ name: "Sales Marketing Network Team" }],
  creator: "Sales Marketing Network",
  publisher: "Sales Marketing Network",
  formatDetection: {
    email: false,
    address: false,
    telephone: false,
  },
  openGraph: {
    type: "website",
    url: "/",
    title: "Sales Marketing Network",
    description:
      "Drive team revenue with shared pipeline management, live collaboration, and performance intelligence.",
    siteName: "Sales Marketing Network",
  },
  twitter: {
    card: "summary_large_image",
    title: "Sales Marketing Network",
    description:
      "A production-ready collaboration and analytics foundation for modern sales teams.",
  },
  robots: {
    index: true,
    follow: true,
  },
};

export const viewport: Viewport = {
  width: "device-width",
  initialScale: 1,
  maximumScale: 1,
  themeColor: [
    { media: "(prefers-color-scheme: light)", color: "#f8fafc" },
    { media: "(prefers-color-scheme: dark)", color: "#020617" },
  ],
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" suppressHydrationWarning>
      <body className={`${inter.variable} ${jetbrainsMono.variable}`}>
        <a className="skip-link" href="#main-content">
          Skip to main content
        </a>

        <div className="app-shell">
          <header className="app-header">
            <div className="container app-header-inner">
              <Link className="brand" href="/" aria-label="Go to homepage">
                <span className="brand-mark" aria-hidden="true">
                  SM
                </span>
                <span className="brand-text">Sales Marketing Network</span>
              </Link>

              <nav className="app-nav" aria-label="Primary">
                <Link href="/">Overview</Link>
                <Link href="/">Pipeline</Link>
                <Link href="/">Analytics</Link>
              </nav>
            </div>
          </header>

          <main id="main-content" className="app-main container">
            {children}
          </main>

          <footer className="app-footer">
            <div className="container app-footer-inner">
              <p>© {new Date().getFullYear()} Sales Marketing Network</p>
              <p className="footer-meta">Built for collaborative sales execution and analytics.</p>
            </div>
          </footer>
        </div>
      </body>
    </html>
  );
}

/* =========================================
   Sales Marketing Network — Global Baseline
   ========================================= */

:root {
  color-scheme: light;

  /* Typography */
  --font-sans: Inter, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  --font-mono: "JetBrains Mono", "SFMono-Regular", Menlo, Monaco, Consolas, "Liberation Mono", monospace;

  /* Core colors */
  --bg: #f8fafc;
  --bg-elevated: #ffffff;
  --bg-subtle: #f1f5f9;
  --text: #0f172a;
  --text-muted: #475569;
  --border: #dbe3ef;

  /* Brand + semantic */
  --brand-50: #eff6ff;
  --brand-500: #2563eb;
  --brand-600: #1d4ed8;
  --brand-700: #1e40af;
  --success: #16a34a;
  --warning: #d97706;
  --danger: #dc2626;

  /* Radius & shadows */
  --radius-xs: 0.375rem;
  --radius-sm: 0.5rem;
  --radius-md: 0.75rem;
  --radius-lg: 1rem;
  --radius-xl: 1.25rem;

  --shadow-sm: 0 1px 2px rgba(15, 23, 42, 0.06);
  --shadow-md: 0 10px 30px rgba(15, 23, 42, 0.08);
  --shadow-lg: 0 18px 40px rgba(15, 23, 42, 0.12);

  /* Layout */
  --container-max: 1200px;
  --header-h: 4.25rem;

  /* Spacing scale */
  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-5: 1.25rem;
  --space-6: 1.5rem;
  --space-8: 2rem;
  --space-10: 2.5rem;
  --space-12: 3rem;

  --transition-fast: 160ms ease;
  --transition-base: 240ms ease;
}

@media (prefers-color-scheme: dark) {
  :root {
    color-scheme: dark;
    --bg: #020617;
    --bg-elevated: #0b1220;
    --bg-subtle: #111827;
    --text: #e2e8f0;
    --text-muted: #94a3b8;
    --border: #1f2a3d;

    --brand-50: #0f172a;
    --brand-500: #3b82f6;
    --brand-600: #2563eb;
    --brand-700: #1d4ed8;

    --shadow-sm: 0 1px 2px rgba(2, 6, 23, 0.45);
    --shadow-md: 0 14px 26px rgba(2, 6, 23, 0.5);
    --shadow-lg: 0 24px 48px rgba(2, 6, 23, 0.6);
  }
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  min-height: 100%;
}

body {
  font-family: var(--font-sans);
  background:
    radial-gradient(circle at 0% 0%, rgba(37, 99, 235, 0.08), transparent 35%),
    radial-gradient(circle at 100% 100%, rgba(14, 165, 233, 0.08), transparent 35%),
    var(--bg);
  color: var(--text);
  line-height: 1.6;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible,
button:focus-visible,
input:focus-visible,
select:focus-visible,
textarea:focus-visible {
  outline: 2px solid var(--brand-500);
  outline-offset: 2px;
}

img,
svg,
video,
canvas {
  max-width: 100%;
  height: auto;
}

.skip-link {
  position: absolute;
  top: -40px;
  left: var(--space-4);
  background: var(--brand-600);
  color: #fff;
  padding: var(--space-2) var(--space-4);
  border-radius: var(--radius-sm);
  z-index: 999;
  transition: top var(--transition-fast);
}

.skip-link:focus {
  top: var(--space-4);
}

.container {
  width: min(100% - 2rem, var(--container-max));
  margin-inline: auto;
}

.app-shell {
  min-height: 100dvh;
  display: grid;
  grid-template-rows: auto 1fr auto;
}

.app-header {
  position: sticky;
  top: 0;
  z-index: 50;
  backdrop-filter: saturate(180%) blur(10px);
  background: color-mix(in oklab, var(--bg-elevated) 82%, transparent);
  border-bottom: 1px solid var(--border);
}

.app-header-inner {
  min-height: var(--header-h);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-3);
  font-weight: 700;
  letter-spacing: -0.015em;
}

.brand-mark {
  width: 2rem;
  height: 2rem;
  display: inline-grid;
  place-items: center;
  border-radius: 999px;
  background: linear-gradient(135deg, var(--brand-500), var(--brand-700));
  color: #fff;
  font-size: 0.75rem;
  box-shadow: var(--shadow-sm);
}

.brand-text {
  font-size: 0.95rem;
  white-space: nowrap;
}

.app-nav {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  flex-wrap: wrap;
}

.app-nav a {
  padding: 0.5rem 0.75rem;
  border-radius: var(--radius-sm);
  color: var(--text-muted);
  font-weight: 500;
  transition: background-color var(--transition-base), color var(--transition-base);
}

.app-nav a:hover {
  background: var(--bg-subtle);
  color: var(--text);
}

.app-main {
  width: 100%;
  padding-top: var(--space-8);
  padding-bottom: var(--space-12);
}

.app-main > * {
  animation: fadeInUp 280ms ease;
}

.app-footer {
  border-top: 1px solid var(--border);
  background: color-mix(in oklab, var(--bg-elevated) 92%, transparent);
}

.app-footer-inner {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2) var(--space-4);
  align-items: center;
  justify-content: space-between;
  padding-block: var(--space-5);
  color: var(--text-muted);
  font-size: 0.9rem;
}

.footer-meta {
  font-size: 0.85rem;
}

/* Utility primitives for upcoming feature work */
.surface {
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
}

.surface-hover {
  transition: transform var(--transition-base), box-shadow var(--transition-base), border-color var(--transition-base);
}

.surface-hover:hover {
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
  border-color: color-mix(in oklab, var(--brand-500) 35%, var(--border));
}

.text-mono {
  font-family: var(--font-mono);
}

.text-muted {
  color: var(--text-muted);
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(4px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@media (max-width: 768px) {
  :root {
    --header-h: 4rem;
  }

  .app-header-inner {
    flex-direction: column;
    align-items: flex-start;
    justify-content: center;
    padding-block: var(--space-3);
  }

  .app-nav {
    width: 100%;
  }

  .app-nav a {
    padding-inline: var(--space-3);
  }

  .app-main {
    padding-top: var(--space-6);
    padding-bottom: var(--space-10);
  }

  .app-footer-inner {
    flex-direction: column;
    align-items: flex-start;
  }
}

@media (prefers-reduced-motion: reduce) {
  * {
    animation: none !important;
    transition: none !important;
    scroll-behavior: auto !important;
  }
}
